  ('heelevel3-d0d1b9a2-moex-00236', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列何者係屬會計師可於查核報告中納入強調事項段之情況？① 對財務報表具重大影響之新', '["對以前年度財務報表所表示之意見已予更新，且與前期所表示者不 同", "對受查者財務狀況或財務績效具重大影響之災害", "重大訴訟或監管措施未來結果之 不確定性", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00237', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '依據品質管理準則1號「會計師事務所之品質管理」，下列何者並非屬於會計師事務所品質管 理制度之八項組成要素？', '["資源", "品質目標", "資訊及溝通", "治理及領導階層"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00238', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '管理階層於財務報表附註後揭露有關該公司於全球各區域廣告支出的明細，以提供財務報表 使用者額外的分析。會計師對該資訊的處理方式，下列何者並不適當？', '["會計師應要求管理階層標示該資訊未經查核", "會計師應評估該等補充資訊之表達方式是否能使其與經查核之財務報表明確區分。若未能 明確區分，應要求管理階層變更該等補充資訊之表達方式", "應對該資訊進行查核，查核意見應涵蓋該資訊", "會計師應閱讀該資訊，確認是否與財務報表之資訊一致"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00239', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '依審計準則570號規定，查核人員於風險評估時辨認出受查者存有繼續經營能力可能產生重 大疑慮之事件或情況，下列敘述何者錯誤？', '["查核人員判斷受查者管理階層採用繼續經營會計基礎編製財務報表係屬不適當時，應表示 「否定意見」", "查核人員判斷管理階層並無意圖清算或停止營業，或除清算或停業外別無實際可行之方案， 惟有繼續經營之能力可能產生重大疑慮之事件或情況仍存有重大不確定性，且其財務報表 已作適當揭露，會計師應於查核報告中納入「繼續經營有關之重大不確定性」段", "查核人員判斷受查者管理階層採用繼續經營會計基礎編製財務報表係屬適當，惟有繼續經 營之能力可能產生重大疑慮之事件或情況仍存有重大不確定性，且其財務報表未作適當揭 露，會計師可能因此表示「保留意見」或「否定意見」", "管理階層對繼續經營能力評估僅6個月（自財務報導結束日起算），並拒絕查核人員延伸評 估之要求，會計師可表示「保留意見」或「否定意見」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00240', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '有關查核人員評估不實表達對財務報表之影響，下列敘述何者錯誤？', '["未更正不實表達不包含顯然微小之不實表達", "查核人員於評估不實表達對財務報表之影響前，不得修正規劃階段決定之重大性", "即使分類之不實表達超過用以評估其他不實表達之重大性，查核人員仍可能作出就財務報 表整體而言該項分類之不實表達非屬重大之結論", "應考量以前期間不重大未更正不實表達之累計數對當期財務報表之影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00241', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '有關查核人員就查核財務報表時所辨認之內部控制缺失與治理單位及管理階層溝通之敘述， 下列何者正確？', '["查核人員依其專業判斷認為以口頭與治理單位溝通內部控制顯著缺失並不適當時，應以書 面為之", "影響相同科目餘額、揭露、攸關聲明之控制或內部控制組成要素存有多項缺失不足以構成 顯著缺失", "以往查核曾與治理單位及管理階層溝通之內部控制顯著缺失未經改正，查核人員詢問管理 階層該等缺失尚未改正之原因獲合理之解釋，則無須於當期重複溝通", "查核人員於解釋內部控制顯著缺失之潛在影響時無須予以量化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00242', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '查核人員於查核規劃階段使用分析性程序的主要目的為何？①協助評估受查者繼續經營能力', '["協助查核人員瞭解受查者之產業及其環境", "辨認並評估可能的重大不實表達風險", "減 少詳細的測試", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00243', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '查核人員為因應管理階層踰越控制之風險，下列何者並非必要的查核程序？', '["測試會計分錄及編製財務報表所作其他調整之適當性", "複核管理階層作會計估計時是否偏頗，並評估造成該偏頗之情況是否顯示存有導因於舞弊 之重大不實表達風險", "就其所辨認之不尋常或非正常營運之重大交易，評估交易之動機及合理性是否顯示該等交 易之進行係用以從事財務報導舞弊或掩飾挪用資產", "對因應管理階層踰越控制風險之控制，執行控制測試"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
